import{_ as t,c as i,o as a,a1 as s}from"./chunks/framework.DILC4Csi.js";const h=JSON.parse('{"title":"Copilot: Premium Requests and Model Usage Details | opencode-mystatus","description":"Learn how to check GitHub Copilot Premium Requests usage. View monthly limits for Free/Pro/Pro+/Business/Enterprise, model details, and overage counts. Supports OAuth Token and Fine-grained PAT authentication.","frontmatter":{"title":"Copilot: Premium Requests and Model Usage Details | opencode-mystatus","sidebarTitle":"Copilot Quota","subtitle":"Copilot: Premium Requests and Model Usage Details","description":"Learn how to check GitHub Copilot Premium Requests usage. View monthly limits for Free/Pro/Pro+/Business/Enterprise, model details, and overage counts. Supports OAuth Token and Fine-grained PAT authentication.","tags":["github-copilot","quota","premium-requests","pat-authentication"],"prerequisite":["/vbgate/opencode-mystatus/start/quick-start"],"order":999},"headers":[],"relativePath":"vbgate/opencode-mystatus/platforms/copilot-usage/index.md","filePath":"vbgate/opencode-mystatus/platforms/copilot-usage/index.md"}'),o={name:"vbgate/opencode-mystatus/platforms/copilot-usage/index.md"};function n(l,e,r,p,d,u){return a(),i("div",null,[...e[0]||(e[0]=[s(`<h1 id="github-copilot-quota-query-premium-requests-and-model-usage-details" tabindex="-1">GitHub Copilot Quota Query: Premium Requests and Model Usage Details <a class="header-anchor" href="#github-copilot-quota-query-premium-requests-and-model-usage-details" aria-label="Permalink to &quot;GitHub Copilot Quota Query: Premium Requests and Model Usage Details&quot;">​</a></h1><h2 id="what-you-ll-learn" tabindex="-1">What You&#39;ll Learn <a class="header-anchor" href="#what-you-ll-learn" aria-label="Permalink to &quot;What You&#39;ll Learn&quot;">​</a></h2><ul><li>Quickly view GitHub Copilot Premium Requests monthly usage</li><li>Understand monthly limit differences for different subscription types (Free / Pro / Pro+ / Business / Enterprise)</li><li>View model usage details (e.g., usage counts for GPT-4, Claude, etc.)</li><li>Identify overage usage and estimate additional costs</li><li>Resolve permission issues with new OpenCode integration (OAuth Token cannot query quota)</li></ul><h2 id="your-current-challenge" tabindex="-1">Your Current Challenge <a class="header-anchor" href="#your-current-challenge" aria-label="Permalink to &quot;Your Current Challenge&quot;">​</a></h2><div class="info custom-block"><p class="custom-block-title">New OpenCode Integration Permission Issue</p><p>OpenCode&#39;s latest OAuth integration no longer grants permission to access the <code>/copilot_internal/*</code> API, causing the original OAuth Token method to fail quota queries.</p><p>You may encounter this error:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>⚠️ GitHub Copilot quota query is temporarily unavailable.</span></span>
<span class="line"><span>OpenCode&#39;s new OAuth integration does not support accessing the quota API.</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Solution:</span></span>
<span class="line"><span>1. Create a fine-grained PAT (visit https://github.com/settings/tokens?type=beta)</span></span>
<span class="line"><span>2. Set &#39;Plan&#39; to &#39;Read-only&#39; in &#39;Account permissions&#39;</span></span>
<span class="line"><span>...</span></span></code></pre></div><p>This is normal. This tutorial will teach you how to resolve it.</p></div><h2 id="core-concepts" tabindex="-1">Core Concepts <a class="header-anchor" href="#core-concepts" aria-label="Permalink to &quot;Core Concepts&quot;">​</a></h2><p>GitHub Copilot quota is divided into the following core concepts:</p><h3 id="premium-requests-main-quota" tabindex="-1">Premium Requests (Main Quota) <a class="header-anchor" href="#premium-requests-main-quota" aria-label="Permalink to &quot;Premium Requests (Main Quota)&quot;">​</a></h3><p>Premium Requests is Copilot&#39;s main quota metric, including:</p><ul><li>Chat interactions (conversing with AI assistant)</li><li>Code Completion (code suggestions)</li><li>Copilot Workspace features (workspace collaboration)</li></ul><div class="tip custom-block"><p class="custom-block-title">What are Premium Requests?</p><p>Simply put: Every time Copilot &quot;does work&quot; for you (generating code, answering questions, analyzing code), it counts as one Premium Request. This is Copilot&#39;s main billing unit.</p></div><h3 id="subscription-types-and-limits" tabindex="-1">Subscription Types and Limits <a class="header-anchor" href="#subscription-types-and-limits" aria-label="Permalink to &quot;Subscription Types and Limits&quot;">​</a></h3><p>Different subscription types have different monthly limits:</p><table tabindex="0"><thead><tr><th>Subscription Type</th><th>Monthly Limit</th><th>Target Audience</th></tr></thead><tbody><tr><td>Free</td><td>50 requests</td><td>Individual developer trial</td></tr><tr><td>Pro</td><td>300 requests</td><td>Individual developer full version</td></tr><tr><td>Pro+</td><td>1,500 requests</td><td>Heavy individual users</td></tr><tr><td>Business</td><td>300 requests</td><td>Team subscription (300 per account)</td></tr><tr><td>Enterprise</td><td>1,000 requests</td><td>Enterprise subscription (1000 per account)</td></tr></tbody></table><h3 id="overage" tabindex="-1">Overage <a class="header-anchor" href="#overage" aria-label="Permalink to &quot;Overage&quot;">​</a></h3><p>If you exceed your monthly limit, Copilot remains usable but incurs additional charges. Overage counts are displayed separately in the output.</p><h2 id="🎒-prerequisites" tabindex="-1">🎒 Prerequisites <a class="header-anchor" href="#🎒-prerequisites" aria-label="Permalink to &quot;🎒 Prerequisites&quot;">​</a></h2><h3 id="before-you-begin" tabindex="-1">Before You Begin <a class="header-anchor" href="#before-you-begin" aria-label="Permalink to &quot;Before You Begin&quot;">​</a></h3><div class="warning custom-block"><p class="custom-block-title">Configuration Check</p><p>This tutorial assumes you have already:</p><ol><li><p>✅ <strong>Installed the opencode-mystatus plugin</strong></p><ul><li>See <a href="./../../start/quick-start/">Quick Start</a></li></ul></li><li><p>✅ <strong>Configured at least one of the following</strong>:</p><ul><li>Logged into GitHub Copilot in OpenCode (OAuth Token)</li><li>Manually created a Fine-grained PAT configuration file (recommended)</li></ul></li></ol></div><h3 id="configuration-methods-choose-one" tabindex="-1">Configuration Methods (Choose One) <a class="header-anchor" href="#configuration-methods-choose-one" aria-label="Permalink to &quot;Configuration Methods (Choose One)&quot;">​</a></h3><h4 id="method-1-using-fine-grained-pat-recommended" tabindex="-1">Method 1: Using Fine-grained PAT (Recommended) <a class="header-anchor" href="#method-1-using-fine-grained-pat-recommended" aria-label="Permalink to &quot;Method 1: Using Fine-grained PAT (Recommended)&quot;">​</a></h4><p>This is the most reliable method, unaffected by OpenCode OAuth integration changes.</p><ol><li>Visit <a href="https://github.com/settings/tokens?type=beta" target="_blank" rel="noreferrer">https://github.com/settings/tokens?type=beta</a></li><li>Click &quot;Generate new token (classic)&quot; or &quot;Generate new token (beta)&quot;</li><li>In &quot;Account permissions&quot;, set <strong>Plan</strong> to <strong>Read-only</strong></li><li>Generate the Token, formatted like <code>github_pat_11A...</code></li><li>Create configuration file <code>~/.config/opencode/copilot-quota-token.json</code>:</li></ol><div class="language-json vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">json</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">{</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  &quot;token&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;github_pat_11A...&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  &quot;username&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;your-username&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  &quot;tier&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;pro&quot;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">}</span></span></code></pre></div><p><strong>Configuration file field descriptions</strong>:</p><ul><li><code>token</code>: Your Fine-grained PAT</li><li><code>username</code>: GitHub username (for API calls)</li><li><code>tier</code>: Subscription type, options: <code>free</code> / <code>pro</code> / <code>pro+</code> / <code>business</code> / <code>enterprise</code></li></ul><h4 id="method-2-using-opencode-oauth-token" tabindex="-1">Method 2: Using OpenCode OAuth Token <a class="header-anchor" href="#method-2-using-opencode-oauth-token" aria-label="Permalink to &quot;Method 2: Using OpenCode OAuth Token&quot;">​</a></h4><p>If you&#39;re already logged into GitHub Copilot in OpenCode, mystatus will attempt to use your OAuth Token.</p><div class="warning custom-block"><p class="custom-block-title">Compatibility Note</p><p>This method may fail due to permission limitations in OpenCode&#39;s OAuth integration. If it fails, please use Method 1 (Fine-grained PAT).</p></div><h2 id="follow-along" tabindex="-1">Follow Along <a class="header-anchor" href="#follow-along" aria-label="Permalink to &quot;Follow Along&quot;">​</a></h2><h3 id="step-1-execute-the-query-command" tabindex="-1">Step 1: Execute the Query Command <a class="header-anchor" href="#step-1-execute-the-query-command" aria-label="Permalink to &quot;Step 1: Execute the Query Command&quot;">​</a></h3><p>Run the slash command in OpenCode:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">/mystatus</span></span></code></pre></div><p><strong>You should see</strong>:</p><p>If you have configured a Copilot account (using Fine-grained PAT or OAuth Token), the output will include content like:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>## GitHub Copilot Account Quota</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Account:        GitHub Copilot (pro)</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Premium Requests [████████░░░░░░░░░░] 40% (180/300)</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Model usage details:</span></span>
<span class="line"><span>  gpt-4: 120 requests</span></span>
<span class="line"><span>  claude-3-5-sonnet: 60 requests</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Period: 2026-01</span></span></code></pre></div><h3 id="step-2-interpret-the-output" tabindex="-1">Step 2: Interpret the Output <a class="header-anchor" href="#step-2-interpret-the-output" aria-label="Permalink to &quot;Step 2: Interpret the Output&quot;">​</a></h3><p>The output contains the following key information:</p><h4 id="_1-account-information" tabindex="-1">1. Account Information <a class="header-anchor" href="#_1-account-information" aria-label="Permalink to &quot;1. Account Information&quot;">​</a></h4><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Account:        GitHub Copilot (pro)</span></span></code></pre></div><p>Displays your Copilot subscription type (pro / free / business, etc.).</p><h4 id="_2-premium-requests-quota" tabindex="-1">2. Premium Requests Quota <a class="header-anchor" href="#_2-premium-requests-quota" aria-label="Permalink to &quot;2. Premium Requests Quota&quot;">​</a></h4><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Premium Requests [████████░░░░░░░░░░] 40% (180/300)</span></span></code></pre></div><ul><li><strong>Progress bar</strong>: Visually shows remaining ratio</li><li><strong>Percentage</strong>: 40% remaining</li><li><strong>Used/Total</strong>: Used 180 requests, total 300 requests</li></ul><div class="tip custom-block"><p class="custom-block-title">Progress Bar Explanation</p><p>Green/yellow fill indicates usage, empty space indicates remaining quota. The more filled, the higher the usage.</p></div><h4 id="_3-model-usage-details-public-api-only" tabindex="-1">3. Model Usage Details (Public API Only) <a class="header-anchor" href="#_3-model-usage-details-public-api-only" aria-label="Permalink to &quot;3. Model Usage Details (Public API Only)&quot;">​</a></h4><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Model usage details:</span></span>
<span class="line"><span>  gpt-4: 120 requests</span></span>
<span class="line"><span>  claude-3-5-sonnet: 60 requests</span></span></code></pre></div><p>Displays usage counts for each model, sorted by usage in descending order (top 5 shown).</p><div class="info custom-block"><p class="custom-block-title">Why don&#39;t I see model details in my output?</p><p>Model details are only displayed when using the Public API (Fine-grained PAT). If you use OAuth Token (Internal API), model details will not be shown.</p></div><h4 id="_4-overage-if-applicable" tabindex="-1">4. Overage (If Applicable) <a class="header-anchor" href="#_4-overage-if-applicable" aria-label="Permalink to &quot;4. Overage (If Applicable)&quot;">​</a></h4><p>If you exceed your monthly limit, it will display:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Overage: 25 requests</span></span></code></pre></div><p>Overage incurs additional charges. Please refer to GitHub Copilot pricing for specific rates.</p><h4 id="_5-reset-time-internal-api-only" tabindex="-1">5. Reset Time (Internal API Only) <a class="header-anchor" href="#_5-reset-time-internal-api-only" aria-label="Permalink to &quot;5. Reset Time (Internal API Only)&quot;">​</a></h4><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Quota reset: 12d 5h (2026-02-01)</span></span></code></pre></div><p>Shows countdown until quota resets.</p><h3 id="step-3-check-common-scenarios" tabindex="-1">Step 3: Check Common Scenarios <a class="header-anchor" href="#step-3-check-common-scenarios" aria-label="Permalink to &quot;Step 3: Check Common Scenarios&quot;">​</a></h3><h4 id="scenario-1-seeing-⚠️-quota-query-temporarily-unavailable" tabindex="-1">Scenario 1: Seeing &quot;⚠️ Quota query temporarily unavailable&quot; <a class="header-anchor" href="#scenario-1-seeing-⚠️-quota-query-temporarily-unavailable" aria-label="Permalink to &quot;Scenario 1: Seeing &quot;⚠️ Quota query temporarily unavailable&quot;&quot;">​</a></h4><p>This is normal, indicating OpenCode&#39;s OAuth Token doesn&#39;t have permission to access the quota API.</p><p><strong>Solution</strong>: Follow &quot;Method 1: Using Fine-grained PAT&quot; to configure a PAT.</p><h4 id="scenario-2-progress-bar-empty-or-nearly-full" tabindex="-1">Scenario 2: Progress Bar Empty or Nearly Full <a class="header-anchor" href="#scenario-2-progress-bar-empty-or-nearly-full" aria-label="Permalink to &quot;Scenario 2: Progress Bar Empty or Nearly Full&quot;">​</a></h4><ul><li><strong>Empty</strong> <code>░░░░░░░░░░░░░░░</code>: Quota exhausted, overage count will be shown</li><li><strong>Nearly full</strong> <code>██████████████████</code>: Nearly exhausted, monitor usage frequency</li></ul><h4 id="scenario-3-displaying-unlimited" tabindex="-1">Scenario 3: Displaying &quot;Unlimited&quot; <a class="header-anchor" href="#scenario-3-displaying-unlimited" aria-label="Permalink to &quot;Scenario 3: Displaying &quot;Unlimited&quot;&quot;">​</a></h4><p>Some Enterprise subscriptions may display &quot;Unlimited&quot;, indicating no limit.</p><h3 id="step-4-handle-errors-if-query-fails" tabindex="-1">Step 4: Handle Errors (If Query Fails) <a class="header-anchor" href="#step-4-handle-errors-if-query-fails" aria-label="Permalink to &quot;Step 4: Handle Errors (If Query Fails)&quot;">​</a></h3><p>If you see the following error:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>GitHub Copilot API request failed (403): Resource not accessible by integration</span></span></code></pre></div><p><strong>Cause</strong>: OAuth Token lacks sufficient permissions to access Copilot API.</p><p><strong>Solution</strong>: Use Fine-grained PAT method (see Method 1).</p><hr><h2 id="checkpoint-✅" tabindex="-1">Checkpoint ✅ <a class="header-anchor" href="#checkpoint-✅" aria-label="Permalink to &quot;Checkpoint ✅&quot;">​</a></h2><p>After completing the steps above, you should be able to:</p><ul><li>[ ] See GitHub Copilot quota information in <code>/mystatus</code> output</li><li>[ ] Understand Premium Requests progress bar and percentage</li><li>[ ] Know your subscription type and monthly limit</li><li>[ ] Know how to view model usage details (if using Fine-grained PAT)</li><li>[ ] Understand what overage means</li></ul><h2 id="common-pitfalls" tabindex="-1">Common Pitfalls <a class="header-anchor" href="#common-pitfalls" aria-label="Permalink to &quot;Common Pitfalls&quot;">​</a></h2><h3 id="pitfall-1-oauth-token-cannot-query-quota-most-common" tabindex="-1">Pitfall 1: OAuth Token Cannot Query Quota (Most Common) <a class="header-anchor" href="#pitfall-1-oauth-token-cannot-query-quota-most-common" aria-label="Permalink to &quot;Pitfall 1: OAuth Token Cannot Query Quota (Most Common)&quot;">​</a></h3><div class="danger custom-block"><p class="custom-block-title">Common Error</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>⚠️ GitHub Copilot quota query is temporarily unavailable.</span></span>
<span class="line"><span>OpenCode&#39;s new OAuth integration does not support accessing the quota API.</span></span></code></pre></div><p><strong>Cause</strong>: OpenCode&#39;s OAuth integration doesn&#39;t grant access permission to the <code>/copilot_internal/*</code> API.</p><p><strong>Solution</strong>: Use Fine-grained PAT method. See &quot;Method 1: Using Fine-grained PAT&quot;.</p></div><h3 id="pitfall-2-incorrect-configuration-file-format" tabindex="-1">Pitfall 2: Incorrect Configuration File Format <a class="header-anchor" href="#pitfall-2-incorrect-configuration-file-format" aria-label="Permalink to &quot;Pitfall 2: Incorrect Configuration File Format&quot;">​</a></h3><p>If the configuration file <code>~/.config/opencode/copilot-quota-token.json</code> has incorrect format, the query will fail.</p><p><strong>Incorrect Example</strong>:</p><div class="language-json vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">json</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">// ❌ Error: Missing username field</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">{</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  &quot;token&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;github_pat_11A...&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  &quot;tier&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;pro&quot;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">}</span></span></code></pre></div><p><strong>Correct Example</strong>:</p><div class="language-json vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">json</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">// ✅ Correct: Contains all required fields</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">{</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  &quot;token&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;github_pat_11A...&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  &quot;username&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;your-username&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  &quot;tier&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;pro&quot;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">}</span></span></code></pre></div><h3 id="pitfall-3-incorrect-subscription-type" tabindex="-1">Pitfall 3: Incorrect Subscription Type <a class="header-anchor" href="#pitfall-3-incorrect-subscription-type" aria-label="Permalink to &quot;Pitfall 3: Incorrect Subscription Type&quot;">​</a></h3><p>If the <code>tier</code> you fill in doesn&#39;t match your actual subscription, the limit calculation will be incorrect.</p><table tabindex="0"><thead><tr><th>Your Actual Subscription</th><th>tier Field Should Be</th><th>Incorrect Example</th></tr></thead><tbody><tr><td>Free</td><td><code>free</code></td><td><code>pro</code> ❌</td></tr><tr><td>Pro</td><td><code>pro</code></td><td><code>free</code> ❌</td></tr><tr><td>Pro+</td><td><code>pro+</code></td><td><code>pro</code> ❌</td></tr><tr><td>Business</td><td><code>business</code></td><td><code>enterprise</code> ❌</td></tr><tr><td>Enterprise</td><td><code>enterprise</code></td><td><code>business</code> ❌</td></tr></tbody></table><p><strong>How to check your actual subscription type</strong>:</p><ul><li>Visit <a href="https://github.com/settings/billing" target="_blank" rel="noreferrer">https://github.com/settings/billing</a></li><li>Check the &quot;GitHub Copilot&quot; section</li></ul><h3 id="pitfall-4-insufficient-token-permissions" tabindex="-1">Pitfall 4: Insufficient Token Permissions <a class="header-anchor" href="#pitfall-4-insufficient-token-permissions" aria-label="Permalink to &quot;Pitfall 4: Insufficient Token Permissions&quot;">​</a></h3><p>If you use a Classic Token (not Fine-grained) without &quot;Plan&quot; read permission, a 403 error will be returned.</p><p><strong>Solution</strong>:</p><ol><li>Ensure you use a Fine-grained Token (generated on the beta version page)</li><li>Ensure you granted &quot;Account permissions → Plan → Read-only&quot;</li></ol><h3 id="pitfall-5-model-details-not-displayed" tabindex="-1">Pitfall 5: Model Details Not Displayed <a class="header-anchor" href="#pitfall-5-model-details-not-displayed" aria-label="Permalink to &quot;Pitfall 5: Model Details Not Displayed&quot;">​</a></h3><div class="tip custom-block"><p class="custom-block-title">Normal Behavior</p><p>If you use OAuth Token (Internal API) method, model usage details won&#39;t be displayed.</p><p>This is because the Internal API doesn&#39;t return model-level usage statistics. If you need model details, please use Fine-grained PAT method.</p></div><h2 id="lesson-summary" tabindex="-1">Lesson Summary <a class="header-anchor" href="#lesson-summary" aria-label="Permalink to &quot;Lesson Summary&quot;">​</a></h2><p>This lesson taught you how to use opencode-mystatus to query GitHub Copilot quota:</p><p><strong>Key Points</strong>:</p><ol><li><strong>Premium Requests</strong> is Copilot&#39;s main quota metric, including Chat, Completion, Workspace, etc.</li><li><strong>Subscription type</strong> determines monthly limit: Free 50, Pro 300, Pro+ 1,500, Business 300, Enterprise 1,000</li><li><strong>Overage</strong> incurs additional charges and is displayed separately in the output</li><li><strong>Fine-grained PAT</strong> is the recommended authentication method, unaffected by OpenCode OAuth integration changes</li><li><strong>OAuth Token</strong> method may fail due to permission limitations and requires PAT as an alternative</li></ol><p><strong>Output Interpretation</strong>:</p><ul><li>Progress bar: Visually shows remaining ratio</li><li>Percentage: Specific remaining amount</li><li>Used/Total: Detailed usage</li><li>Model details (optional): Usage counts for each model</li><li>Reset time (optional): Countdown until next reset</li></ul><h2 id="coming-up-next" tabindex="-1">Coming Up Next <a class="header-anchor" href="#coming-up-next" aria-label="Permalink to &quot;Coming Up Next&quot;">​</a></h2><blockquote><p>In the next lesson, we&#39;ll learn about <strong><a href="./../../advanced/copilot-auth/">Copilot Authentication Configuration</a></strong>.</p><p>You&#39;ll learn:</p><ul><li>Detailed comparison between OAuth Token and Fine-grained PAT</li><li>How to generate Fine-grained PAT (complete steps)</li><li>Multiple solutions to permission issues</li><li>Best practices for different scenarios</li></ul></blockquote><hr><h2 id="appendix-source-code-reference" tabindex="-1">Appendix: Source Code Reference <a class="header-anchor" href="#appendix-source-code-reference" aria-label="Permalink to &quot;Appendix: Source Code Reference&quot;">​</a></h2><details><summary><strong>Click to expand source code locations</strong></summary><blockquote><p>Last updated: 2026-01-23</p></blockquote><table tabindex="0"><thead><tr><th>Function</th><th>File Path</th><th>Lines</th></tr></thead><tbody><tr><td>Copilot quota query</td><td><a href="https://github.com/vbgate/opencode-mystatus/blob/main/plugin/lib/copilot.ts" target="_blank" rel="noreferrer"><code>plugin/lib/copilot.ts</code></a></td><td>481-524</td></tr><tr><td>---</td><td>---</td><td>---</td></tr><tr><td>Public Billing API query</td><td><a href="https://github.com/vbgate/opencode-mystatus/blob/main/plugin/lib/copilot.ts" target="_blank" rel="noreferrer"><code>plugin/lib/copilot.ts</code></a></td><td>157-177</td></tr><tr><td>Internal API query</td><td><a href="https://github.com/vbgate/opencode-mystatus/blob/main/plugin/lib/copilot.ts" target="_blank" rel="noreferrer"><code>plugin/lib/copilot.ts</code></a></td><td>242-304</td></tr><tr><td>Token exchange logic</td><td><a href="https://github.com/vbgate/opencode-mystatus/blob/main/plugin/lib/copilot.ts" target="_blank" rel="noreferrer"><code>plugin/lib/copilot.ts</code></a></td><td>183-208</td></tr><tr><td>Internal API formatting</td><td><a href="https://github.com/vbgate/opencode-mystatus/blob/main/plugin/lib/copilot.ts" target="_blank" rel="noreferrer"><code>plugin/lib/copilot.ts</code></a></td><td>354-393</td></tr><tr><td>Public API formatting</td><td><a href="https://github.com/vbgate/opencode-mystatus/blob/main/plugin/lib/copilot.ts" target="_blank" rel="noreferrer"><code>plugin/lib/copilot.ts</code></a></td><td>410-468</td></tr><tr><td>Copilot subscription type definition</td><td><a href="https://github.com/vbgate/opencode-mystatus/blob/main/plugin/lib/types.ts" target="_blank" rel="noreferrer"><code>plugin/lib/types.ts</code></a></td><td>57-58</td></tr><tr><td>CopilotQuotaConfig type definition</td><td><a href="https://github.com/vbgate/opencode-mystatus/blob/main/plugin/lib/types.ts" target="_blank" rel="noreferrer"><code>plugin/lib/types.ts</code></a></td><td>66-73</td></tr><tr><td>CopilotAuthData type definition</td><td><a href="https://github.com/vbgate/opencode-mystatus/blob/main/plugin/lib/types.ts" target="_blank" rel="noreferrer"><code>plugin/lib/types.ts</code></a></td><td>46-51</td></tr><tr><td>Copilot subscription limit constants</td><td><a href="https://github.com/vbgate/opencode-mystatus/blob/main/plugin/lib/copilot.ts" target="_blank" rel="noreferrer"><code>plugin/lib/copilot.ts</code></a></td><td>397-403</td></tr></tbody></table><p><strong>Key Constants</strong>:</p><ul><li><p><code>COPILOT_PLAN_LIMITS</code>: Monthly limits for each subscription type (lines 397-403)</p><ul><li><code>free: 50</code></li><li><code>pro: 300</code></li><li><code>pro+: 1500</code></li><li><code>business: 300</code></li><li><code>enterprise: 1000</code></li></ul></li><li><p><code>COPILOT_QUOTA_CONFIG_PATH</code>: Fine-grained PAT configuration file path (lines 93-98)</p><ul><li><code>~/.config/opencode/copilot-quota-token.json</code></li></ul></li></ul><p><strong>Key Functions</strong>:</p><ul><li><code>queryCopilotUsage()</code>: Main query function, supports two authentication strategies (lines 481-524)</li><li><code>fetchPublicBillingUsage()</code>: Query Public Billing API using Fine-grained PAT (lines 157-177)</li><li><code>fetchCopilotUsage()</code>: Query Internal API using OAuth Token (lines 242-304)</li><li><code>exchangeForCopilotToken()</code>: OAuth Token exchange logic (lines 183-208)</li><li><code>formatPublicBillingUsage()</code>: Public API response formatting, includes model details (lines 410-468)</li><li><code>formatCopilotUsage()</code>: Internal API response formatting (lines 354-393)</li></ul><p><strong>Authentication Strategies</strong>:</p><ol><li><p><strong>Strategy 1 (Priority)</strong>: Fine-grained PAT + Public Billing API</p><ul><li>Pros: Stable, unaffected by OpenCode OAuth integration changes</li><li>Cons: Requires manual PAT configuration by user</li></ul></li><li><p><strong>Strategy 2 (Fallback)</strong>: OAuth Token + Internal API</p><ul><li>Pros: No additional configuration required</li><li>Cons: May fail due to permission limitations (current OpenCode integration doesn&#39;t support)</li></ul></li></ol><p><strong>API Endpoints</strong>:</p><ul><li>Public Billing API: <code>https://api.github.com/users/{username}/settings/billing/premium_request/usage</code></li><li>Internal Quota API: <code>https://api.github.com/copilot_internal/user</code></li><li>Token Exchange API: <code>https://api.github.com/copilot_internal/v2/token</code></li></ul></details>`,104)])])}const g=t(o,[["render",n]]);export{h as __pageData,g as default};
